<script setup>import{computed,reactive}from"vue";const defaults={annualIncome:180000,socialInsurance:24000,specialDeductions:12000,otherDeductions:0,prepaidTax:6000},form=reactive({...defaults}),brackets=[{ceiling:36000,rate:.03,deduction:0},{ceiling:144000,rate:.1,deduction:2520},{ceiling:300000,rate:.2,deduction:16920},{ceiling:420000,rate:.25,deduction:31920},{ceiling:660000,rate:.3,deduction:52920},{ceiling:960000,rate:.35,deduction:85920},{ceiling:Infinity,rate:.45,deduction:181920}];const taxable=computed(()=>Math.max(0,+form.annualIncome-60000-(+form.socialInsurance)-(+form.specialDeductions)-(+form.otherDeductions))),bracket=computed(()=>brackets.find(x=>taxable.value<=x.ceiling)),tax=computed(()=>Math.max(0,taxable.value*bracket.value.rate-bracket.value.deduction)),settlement=computed(()=>tax.value-(+form.prepaidTax)),rate=computed(()=>form.annualIncome?tax.value/form.annualIncome*100:0),money=v=>Number(v).toLocaleString('zh-CN',{minimumFractionDigits:2,maximumFractionDigits:2});</script>
<template><view class="page"><view class="hero"><text class="eyebrow">个人所得税</text><text class="title">年度综合所得税测算</text><text class="subtle">独立计算，不写入账本。</text></view><view class="card"><view class="card-title"><text>输入年度数据</text><text class="muted" @click="Object.assign(form,defaults)">重置示例</text></view><label class="field">年度综合所得<input v-model.number="form.annualIncome" class="input" type="digit"/></label><label class="field">专项扣除（社保、公积金等）<input v-model.number="form.socialInsurance" class="input" type="digit"/></label><label class="field">专项附加扣除<input v-model.number="form.specialDeductions" class="input" type="digit"/></label><label class="field">其他依法扣除及捐赠<input v-model.number="form.otherDeductions" class="input" type="digit"/></label><label class="field">年度已预缴税额<input v-model.number="form.prepaidTax" class="input" type="digit"/></label></view><view class="result card"><text>预计年度应纳税额</text><text class="strong">¥ {{money(tax)}}</text><view class="line"><text>应纳税所得额</text><text>¥{{money(taxable)}}</text></view><view class="line"><text>适用税率</text><text>{{bracket.rate*100}}%</text></view><view class="line"><text>速算扣除数</text><text>¥{{money(bracket.deduction)}}</text></view><view class="line"><text>综合税负率</text><text>{{rate.toFixed(2)}}%</text></view><view :class="['settlement',settlement>0?'due':'refund']"><text>{{settlement>0?'预计需补税':settlement<0?'预计可退税':'预计无需补退'}}</text><text class="strong">¥{{money(Math.abs(settlement))}}</text></view></view><view class="notice">本工具按中国居民个人年度综合所得通用公式估算，仅供参考，最终以税务机关核定为准。</view></view></template>
<style scoped>.result>text{display:block;color:#887e71}.result>.strong{display:block;margin:18rpx 0 28rpx;font-size:50rpx}.line{display:flex;justify-content:space-between;padding:15rpx 0;border-bottom:1rpx solid #eee7dd}.settlement{display:flex;justify-content:space-between;margin-top:26rpx;padding:24rpx;border-radius:20rpx}.due{background:#fff0e9;color:#b6563c}.refund{background:#e8f5ed;color:#3f825f}.notice{padding:20rpx;color:#8d8378;font-size:23rpx;line-height:1.6}</style>


